<?php session_start(); require_once __DIR__.'/../includes/functions.php'; $err=''; if($_SERVER['REQUEST_METHOD']==='POST'){ if(!csrf_verify()){ $err='Sessão expirada. Tente novamente.'; } else { $u=$_POST['user']??''; $p=$_POST['pass']??''; if($u===cfg('admin_user') && password_verify($p,cfg('admin_pass_hash'))){ session_regenerate_id(true); $_SESSION['admin']=true; header('Location: /admin/index.php'); exit;} $err='Usuário ou senha inválidos.'; } } ?>
